import{_ as e,o as t,c as r,ag as o}from"./chunks/framework.C9sp7nFj.js";const f=JSON.parse('{"title":"境外安全注意事项","description":"出国旅行的安全注意事项和防范措施","frontmatter":{"title":"境外安全注意事项","description":"出国旅行的安全注意事项和防范措施"},"headers":[],"relativePath":"knowledge/safety/abroad-safety.md","filePath":"knowledge/safety/abroad-safety.md","lastUpdated":null}'),l={name:"knowledge/safety/abroad-safety.md"};function d(n,a,i,s,h,c){return t(),r("div",null,[...a[0]||(a[0]=[o('<h1 id="境外安全注意事项" tabindex="-1">境外安全注意事项 <a class="header-anchor" href="#境外安全注意事项" aria-label="Permalink to &quot;境外安全注意事项&quot;">​</a></h1><h2 id="行前安全准备" tabindex="-1">行前安全准备 <a class="header-anchor" href="#行前安全准备" aria-label="Permalink to &quot;行前安全准备&quot;">​</a></h2><p>了解目的地的安全状况，注册中国领事服务网的&quot;出国及海外中国公民自愿登记&quot;。告知家人行程安排。</p><h2 id="住宿安全" tabindex="-1">住宿安全 <a class="header-anchor" href="#住宿安全" aria-label="Permalink to &quot;住宿安全&quot;">​</a></h2><p>选择位于安全区域的住宿。入住时确认逃生通道位置，使用门链和保险锁。</p><h2 id="交通安全" tabindex="-1">交通安全 <a class="header-anchor" href="#交通安全" aria-label="Permalink to &quot;交通安全&quot;">​</a></h2><p>使用正规出租车或网约车。夜间避免单独乘坐不明来源的交通工具。</p><h2 id="饮食安全" tabindex="-1">饮食安全 <a class="header-anchor" href="#饮食安全" aria-label="Permalink to &quot;饮食安全&quot;">​</a></h2><p>谨慎食用生冷食物和街头摊贩。饮用瓶装水或确认水质安全。</p><h2 id="防盗防骗" tabindex="-1">防盗防骗 <a class="header-anchor" href="#防盗防骗" aria-label="Permalink to &quot;防盗防骗&quot;">​</a></h2><p>贵重物品分开放置，使用隐蔽腰包。警惕街头诈骗和过于热情的陌生人。</p>',11)])])}const _=e(l,[["render",d]]);export{f as __pageData,_ as default};
